mapper.insert:
INSERT INTO ATTENDANCE_REQUESTS (
    ATTENDANCE_RECORD_ID, USER_ID, TYPE, REQUESTED_CHECK_IN_AT, REQUESTED_CHECK_OUT_AT, REASON, STATUS
) VALUES (
    #{attendanceRecordId}, #{userId}, #{type}, #{requestedCheckInAt}, #{requestedCheckOutAt}, #{reason}, #{status}
)

mapper.select:
SELECT ID, ATTENDANCE_RECORD_ID, USER_ID, TYPE, REQUESTED_CHECK_IN_AT, REQUESTED_CHECK_OUT_AT, REASON, STATUS, CREATED_AT
FROM ATTENDANCE_REQUESTS
WHERE ID = #{id}

mapper.update:
UPDATE ATTENDANCE_REQUESTS
SET STATUS = #{status}
WHERE ID = #{id}

mapper.select:
SELECT COUNT(*)
FROM ATTENDANCE_REQUESTS
WHERE ATTENDANCE_RECORD_ID = #{attendanceRecordId}
  AND USER_ID = #{userId}
  AND STATUS = 'PENDING'

SELECT ar.ID AS requestId, ar.ATTENDANCE_RECORD_ID AS attendanceRecordId, ar.USER_ID AS userId, u.NAME AS userName, rec.WORK_DATE AS workDate, ar.TYPE AS type, ar.REQUESTED_CHECK_IN_AT AS requestedCheckInAt, ar.REQUESTED_CHECK_OUT_AT AS requestedCheckOutAt, ar.REASON AS reason, ar.STATUS AS status, ar.CREATED_AT AS requestedAt FROM ATTENDANCE_REQUESTS ar JOIN ATTENDANCE_RECORDS rec ON rec.ID = ar.ATTENDANCE_RECORD_ID JOIN USERS u ON u.ID = ar.USER_ID WHERE rec.WORKPLACE_ID = #{workplaceId}
AND ar.STATUS = #{status}
ORDER BY ar.CREATED_AT DESC, ar.ID DESC
